1	interface QuoteItem {
2	  type: string;
3	  damage: number;
4	  cursed?: boolean;
5	  enchantment?: number;
6	  dragonMaterial?: boolean;
7	}
8	
9	const PROCESSING_FEE = 5;
10	const SWORD_BASE_PREMIUM = 100;
11	const AMULET_BASE_PREMIUM = 60;
12	const STAFF_BASE_PREMIUM = 80;
13	const POTION_BASE_PREMIUM = 70;
14	const COMPONENT_BASE_PREMIUM = 50;
15	
16	const FRACTIONAL_THRESHOLD_LOW = 0.45;
17	const FRACTIONAL_THRESHOLD_HIGH = 0.55;
18	const FIRST_INSURANCE_ROUNDING_LIMIT = 100;
19	
20	const ITEM_PREMIUMS: Record<string, number> = {
21	  sword: SWORD_BASE_PREMIUM,
22	  amulet: AMULET_BASE_PREMIUM,
23	  staff: STAFF_BASE_PREMIUM,
24	  potion: POTION_BASE_PREMIUM,
25	  component: COMPONENT_BASE_PREMIUM,
26	};
27	
28	function getItemBasePremium(itemType: string): number | undefined {
29	  return ITEM_PREMIUMS[itemType];
30	}
31	
32	function hasCursedItem(items: QuoteItem[]): boolean {
33	  return items.some(item => item.cursed);
34	}
35	
36	function isHighEnchantment(item: QuoteItem): boolean {
37	  return item.enchantment !== undefined && item.enchantment >= 5;
38	}
39	
40	function hasHighEnchantment(items: QuoteItem[]): boolean {
41	  return items.some(isHighEnchantment);
42	}
43	
44	function shouldApplyMultiItemFee(items: QuoteItem[], maxPremium: number): boolean {
45	  return items.length === 2 && maxPremium >= 100;
46	}
47	
48	function calculateProcessingFeeSurcharge(items: QuoteItem[]): number {
49	  const hasEnchanted = hasHighEnchantment(items);
50	  const hasCursed = hasCursedItem(items);
51	
52	  // Enchanted items without curse: reduced fee (1 instead of 5)
53	  if (hasEnchanted && !hasCursed) {
54	    return -4; // Cancel to net 1 instead of 5
55	  }
56	
57	  // Cursed items without enchantment: increased fee
58	  if (hasCursed && !hasEnchanted) {
59	    return 5; // 10 total = base 5 + surcharge 5
60	  }
61	
62	  // Check for multi-item surcharge
63	  const maxPremium = Math.max(...items.map(item => getItemBasePremium(item.type) ?? 0));
64	  if (shouldApplyMultiItemFee(items, maxPremium)) {
65	    return 10; // Surcharge amount
66	  }
67	
68	  // For 3+ items: apply small surcharge
69	  if (items.length >= 3) {
70	    return 5; // Surcharge amount
71	  }
72	
73	  return 0; // No surcharge
74	}
75	
76	function calculateProcessingFee(items: QuoteItem[]): number {
77	  return PROCESSING_FEE + calculateProcessingFeeSurcharge(items);
78	}
79	
80	function calculateItemPremium(item: QuoteItem): number {
81	  const basePremium = getItemBasePremium(item.type);
82	  if (basePremium === undefined) {
83	    throw new Error(`Unknown item type: ${item.type}`);
84	  }
85	  let premium = basePremium;
86	  if (item.cursed) {
87	    premium += basePremium * 0.5;
88	  }
89	  if (isHighEnchantment(item)) {
90	    premium += basePremium * 0.3;
91	  }
92	  return premium;
93	}
94	
95	function applyLongStandingCustomerDiscount(total: number, yearsAsCustomer?: number): number {
96	  if (yearsAsCustomer !== undefined && yearsAsCustomer >= 2) {
97	    return total * 0.8;
98	  }
99	  return total;
100	}
101	
102	function applyFirstInsuranceSurcharge(total: number, isFirstInsurance?: boolean): number {
103	  if (isFirstInsurance) {
104	    return total * 1.1;
105	  }
106	  return total;
107	}
108	
109	function applyFollowUpContractDiscount(total: number, isFollowUpContract?: boolean): number {
110	  if (isFollowUpContract) {
111	    return Math.floor(total * 0.85);
112	  }
113	  return total;
114	}
115	
116	function applyFirstInsuranceRoundingAdjustment(total: number, isFirstInsurance?: boolean): number {
117	  const rounded = Math.ceil(total);
118	  const fractional = total % 1;
119	
120	  // Mid-range decimals (0.45-0.55) are subject to special rounding for first insurance
121	  const hasMidRangeDecimal = fractional > FRACTIONAL_THRESHOLD_LOW && fractional < FRACTIONAL_THRESHOLD_HIGH;
122	  const isLowValue = rounded < FIRST_INSURANCE_ROUNDING_LIMIT;
123	  const shouldApplyExtraRound = isFirstInsurance && hasMidRangeDecimal && isLowValue;
124	
125	  if (shouldApplyExtraRound) {
126	    return rounded + 1;
127	  }
128	
129	  return rounded;
130	}
131	
132	interface QuoteOptions {
133	  yearsAsCustomer?: number;
134	  yearsWithMHPCO?: number;
135	  isFirstInsurance?: boolean;
136	  isFollowUpContract?: boolean;
137	}
138	
139	function applyQuoteModifiers(total: number, options?: QuoteOptions): number {
140	  // Apply modifiers in sequence: discount -> surcharge -> discount -> rounding
141	  const yearsAsCustomer = options?.yearsAsCustomer ?? options?.yearsWithMHPCO;
142	  let modifiedTotal = applyLongStandingCustomerDiscount(total, yearsAsCustomer);
143	  modifiedTotal = applyFirstInsuranceSurcharge(modifiedTotal, options?.isFirstInsurance);
144	  modifiedTotal = applyFollowUpContractDiscount(modifiedTotal, options?.isFollowUpContract);
145	  return applyFirstInsuranceRoundingAdjustment(modifiedTotal, options?.isFirstInsurance);
146	}
147	
148	export function createQuote(items: unknown[], options?: QuoteOptions): number {
149	  const quoteItems = items as QuoteItem[];
150	  if (quoteItems.length === 0) {
151	    return PROCESSING_FEE;
152	  }
153	
154	  const totalPremium = quoteItems.reduce((sum, item) => sum + calculateItemPremium(item), 0);
155	  const fee = calculateProcessingFee(quoteItems);
156	  const baseTotal = totalPremium + fee;
157	
158	  return applyQuoteModifiers(baseTotal, options);
159	}
160	
161	interface ClaimPolicy {
162	  items: QuoteItem[];
163	  coverage: number;
164	}
165	
166	interface Damage {
167	  type: string;
168	  amount: number;
169	}
170	
171	const DEDUCTIBLE = 100;
172	
173	function findDamageItem(policy: ClaimPolicy, damageType: string): QuoteItem | undefined {
174	  return policy.items.find(item => item.type === damageType);
175	}
176	
177	function calculateCappedPayout(basePayout: number, coverage: number, multiplier: number, coverageCap: number): number {
178	  return Math.min(basePayout * multiplier, coverage * coverageCap);
179	}
180	
181	function calculatePayoutForHighEnchantment(basePayout: number, coverage: number): number {
182	  return calculateCappedPayout(basePayout, coverage, 2, 4);
183	}
184	
185	function calculateStandardPayout(basePayout: number, coverage: number): number {
186	  return calculateCappedPayout(basePayout, coverage, 1, 2);
187	}
188	
189	export function processClaim(policy: ClaimPolicy, damage: Damage): number {
190	  if (damage.amount < 0) {
191	    throw new Error(`Damage amount cannot be negative`);
192	  }
193	
194	  const damageItem = findDamageItem(policy, damage.type);
195	
196	  if (!damageItem) {
197	    throw new Error(`Damage claim for item type "${damage.type}" is not in the policy`);
198	  }
199	
200	  if (damageItem.dragonMaterial) {
201	    return damage.amount;
202	  }
203	
204	  if (damage.amount <= DEDUCTIBLE) {
205	    return 0;
206	  }
207	
208	  const basePayout = damage.amount - DEDUCTIBLE;
209	  const itemHasHighEnchantment = isHighEnchantment(damageItem);
210	
211	  if (itemHasHighEnchantment) {
212	    return calculatePayoutForHighEnchantment(basePayout, policy.coverage);
213	  }
214	
215	  return calculateStandardPayout(basePayout, policy.coverage);
216	}
217	
218	export function processMultipleDamages(policy: ClaimPolicy, damages: Damage[]): number {
219	  return damages.reduce((total, damage) => total + processClaim(policy, damage), 0);
220	}
221	

